cat << 'EOF' > patch-runner.js
const fs = require('fs');
const file = 'src/utils/agent_runner.ts';
let code = fs.readFileSync(file, 'utf8');

code = code.replace(
  /persistWork\?: \(\) => Promise<PersistWorkResult>;/,
  'persistWork?: () => Promise<PersistWorkResult>;
	persistQa?: () => Promise<PersistWorkResult>;'
);

const oldPersistWorkBlock = `			if (!options.persistWork) {
				outputs.push(
					JSON.stringify(
						{
							ok: false,
							error_code: "persist_not_available",
							message:
								'persist_work is not available for this persona. Use "run_shell" instead.',
						},
						null,
						2,
					),
				);
				continue;
			}

			const result = await options.persistWork();
			outputs.push(JSON.stringify(result, null, 2));`;

const newBlock = `			if (action.type === "persist_qa") {
				if (!options.persistQa) {
					outputs.push(
						JSON.stringify(
							{
								ok: false,
								error_code: "persist_qa_not_available",
								message: 'persist_qa is not available for this persona.',
							},
							null,
							2,
						),
					);
					continue;
				}
				const result = await options.persistQa();
				outputs.push(JSON.stringify(result, null, 2));
				continue;
			}

			if (action.type === "persist_work") {
				if (!options.persistWork) {
					outputs.push(
						JSON.stringify(
							{
								ok: false,
								error_code: "persist_not_available",
								message:
									'persist_work is not available for this persona. Use "run_shell" instead.',
							},
							null,
							2,
						),
					);
					continue;
				}

				const result = await options.persistWork();
				outputs.push(JSON.stringify(result, null, 2));
				continue;
			}`;

code = code.replace(oldPersistWorkBlock, newBlock);

fs.writeFileSync(file, code);
EOF
